// Only run on the first Monday of the month
const today = new Date();
if (today.getDate() > 7) {
  return [];
}
return [{ json: { run: true, report_month: today.toISOString().substring(0, 7) + '-01' } }];

const userId = $('Get User Personas').item.json.user_id;
const persona = $('Get User Personas').item.json.persona;
const reportMonth = $('Check First Monday').item.json.report_month;
const entries = $('Get Persona Entries').all().map(i => i.json);

const breakdown = { pain: 0, desire: 0, language: 0, criteria: 0 };
for (const e of entries) {
  if (breakdown[e.dimension] !== undefined) breakdown[e.dimension]++;
}

const topPains = entries.filter(e => e.dimension === 'pain').slice(0, 5);
const topDesires = entries.filter(e => e.dimension === 'desire').slice(0, 5);
const topLanguage = entries.filter(e => e.dimension === 'language').slice(0, 5);
const topCriteria = entries.filter(e => e.dimension === 'criteria').slice(0, 5);

const monthName = new Date(reportMonth).toLocaleDateString('en-US', { month: 'long', year: 'numeric' });
const title = `${persona} — ${monthName}`;

const md = `# ${title}\n\n**Entries:** ${entries.length} (${breakdown.pain} pains, ${breakdown.desire} desires, ${breakdown.language} language, ${breakdown.criteria} criteria)\n\n---\n\n## Top Pains\n${topPains.map(p => `- ${p.text} (${p.frequency}x, ${p.trend})`).join('\n') || 'None detected'}\n\n## Top Desires\n${topDesires.map(p => `- ${p.text} (${p.frequency}x, ${p.trend})`).join('\n') || 'None detected'}\n\n## Language Patterns\n${topLanguage.map(p => `- ${p.text} (${p.frequency}x, ${p.trend})`).join('\n') || 'None detected'}\n\n## Decision Criteria\n${topCriteria.map(p => `- ${p.text} (${p.frequency}x, ${p.trend})`).join('\n') || 'None detected'}\n\n---\n*Generated by Signal Plane VoC Research*`;

const contentJson = {
  top_pains: topPains,
  top_desires: topDesires,
  top_language: topLanguage,
  top_criteria: topCriteria
};

return [{
  json: {
    user_id: userId,
    persona: persona,
    report_month: reportMonth,
    title: title,
    content_json: JSON.stringify(contentJson),
    content_md: md,
    entry_count: entries.length,
    dimension_breakdown: JSON.stringify(breakdown),
    language_shifts: '[]'
  }
}];
